# Capture stderr vs stdout separately
for f in help version cmd-help err-bad-float err-empty-float err-nofile err-unknown err-completion-noshell err-badshell completion-help; do
  echo "=== $f ==="
  case $f in
    help) /workspace/executable --help > /tmp/stdout 2> /tmp/stderr ;;
    version) /workspace/executable --version > /tmp/stdout 2> /tmp/stderr ;;
    cmd-help) /workspace/executable help > /tmp/stdout 2> /tmp/stderr ;;
    err-bad-float) /workspace/executable -H abc > /tmp/stdout 2> /tmp/stderr ;;
    err-empty-float) /workspace/executable -H "" > /tmp/stdout 2> /tmp/stderr ;;
    err-nofile) /workspace/executable - > /tmp/stdout 2> /tmp/stderr ;;
    err-unknown) /workspace/executable --bogus > /tmp/stdout 2> /tmp/stderr ;;
    err-completion-noshell) /workspace/executable completion > /tmp/stdout 2> /tmp/stderr ;;
    err-badshell) /workspace/executable completion notashell > /tmp/stdout 2> /tmp/stderr ;;
    completion-help) /workspace/executable completion --help > /tmp/stdout 2> /tmp/stderr ;;
  esac
  rc=$?
  echo "  EXIT=$rc"
  echo "  STDOUT bytes: $(wc -c < /tmp/stdout)"
  echo "  STDERR bytes: $(wc -c < /tmp/stderr)"
done

